// // This module implements a 16-bit down/up counter with an enable signal. The counter decrements when the `up_down` signal is high and increments when it is low. The counter resets to 0 when the `reset` signal is asserted. The output is a 16-bit value representing the current count.
module counter (
    input wire clk,
    input wire reset,
    input wire enable,
    input wire up_down, // 1 for up, 0 for down
    output reg [15:0] count
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        count <= 16'b0;
    end else if (enable) begin
        if (up_down) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
end

endmodule
